def format_activity(activity):
    if activity['type'] == 'type1':
        return {
            'id': activity['id'],
            'name': activity['name'],
            'details': activity['details'],
            'formatted_date': activity['date'].strftime('%Y-%m-%d')
        }
    elif activity['type'] == 'type2':
        return {
            'id': activity['id'],
            'title': activity['title'],
            'description': activity['description'],
            'formatted_date': activity['date'].strftime('%Y-%m-%d')
        }
    elif activity['type'] == 'type3':
        return {
            'id': activity['id'],
            'event_name': activity['event_name'],
            'location': activity['location'],
            'formatted_date': activity['date'].strftime('%Y-%m-%d')
        }
    else:
        return None

def get_activities():
    raw_activities = fetch_activities_from_elasticsearch()  # Assuming this function fetches raw data
    formatted_activities = [format_activity(activity) for activity in raw_activities]
    return formatted_activities

def solve(*args):
    return get_activities()
